import pandas as pd
import numpy as np
from openai import OpenAI
import json, io, sys

client = OpenAI()

class DataAnalysisAgent:
    def __init__(self, df: pd.DataFrame, dataset_name: str = "dataset"):
        self.df = df
        self.dataset_name = dataset_name
        self.profile = self._profile_data()
        self.history = []
        self.artifacts = {}

    def _profile_data(self) -> dict:
        """Build a compact data profile for LLM context injection."""
        profile = {
            "shape": list(self.df.shape),
            "columns": {},
            "null_counts": self.df.isnull().sum().to_dict(),
        }
        for col in self.df.columns:
            dtype = str(self.df[col].dtype)
            if self.df[col].dtype in [np.float64, np.int64]:
                profile["columns"][col] = {
                    "dtype": dtype,
                    "min": float(self.df[col].min()),
                    "max": float(self.df[col].max()),
                    "mean": float(self.df[col].mean()),
                    "std": float(self.df[col].std()),
                }
            else:
                vc = self.df[col].value_counts()
                profile["columns"][col] = {
                    "dtype": dtype,
                    "unique": int(self.df[col].nunique()),
                    "top_values": vc.head(5).to_dict(),
                }
        return profile

    def _generate_plan(self, question: str) -> list[dict]:
        """Generate a structured analysis plan."""
        messages = [
            {"role": "system", "content": f"""You are a data analyst.
Dataset '{self.dataset_name}' profile: {json.dumps(self.profile, default=str)}
Generate a JSON analysis plan as a list of steps.
Each step: {{"step": int, "description": str, "code": str (Python), "output_var": str}}
The variable 'df' contains the dataset. Use pandas operations only.
Return ONLY valid JSON."""},
            {"role": "user", "content": question}
        ]
        response = client.chat.completions.create(
            model="gpt-4o", messages=messages, temperature=0,
            response_format={"type": "json_object"}
        )
        result = json.loads(response.choices[0].message.content)
        return result.get("steps", [])

    def _execute_step(self, step: dict) -> tuple[bool, str, any]:
        """Execute a plan step in a controlled environment."""
        local_vars = {"df": self.df, "pd": pd, "np": np, **self.artifacts}
        output_capture = io.StringIO()

        try:
            sys.stdout = output_capture
            exec(step["code"], local_vars)
            sys.stdout = sys.__stdout__

            output_var = step.get("output_var")
            result = local_vars.get(output_var) if output_var else None
            if output_var and result is not None:
                self.artifacts[output_var] = result

            stdout = output_capture.getvalue()
            return True, stdout, result
        except Exception as e:
            sys.stdout = sys.__stdout__
            return False, str(e), None

    def _synthesize_insights(self, question: str, results: list) -> str:
        """Generate narrative insights from collected results."""
        results_summary = []
        for r in results:
            if isinstance(r["result"], pd.DataFrame):
                results_summary.append(f"Step {r['step']}: DataFrame {r['result'].shape}\n{r['result'].head(10).to_string()}")
            elif r["result"] is not None:
                results_summary.append(f"Step {r['step']}: {r['result']}")
            if r["stdout"]:
                results_summary.append(f"Output: {r['stdout'][:500]}")

        messages = [
            {"role": "system", "content": "You are a data analyst. Write clear, specific insights."},
            {"role": "user", "content": f"""Question: {question}
Analysis results:
{chr(10).join(results_summary)}

Write:
1. Executive summary (2-3 sentences with specific numbers)
2. Key findings (3-5 bullet points)
3. Recommended actions
4. Data caveats"""}
        ]
        response = client.chat.completions.create(model="gpt-4o", messages=messages)
        return response.choices[0].message.content

    def analyze(self, question: str) -> dict:
        """Run the full analysis pipeline."""
        plan = self._generate_plan(question)
        results = []

        for step in plan:
            success, output, result = self._execute_step(step)

            if not success:
                # Self-correction: retry with error context
                fix_messages = [
                    {"role": "system", "content": f"Fix this Python code error.\nCode:\n{step['code']}\nError: {output}\nReturn only the fixed code."},
                    {"role": "user", "content": "Fix the code."}
                ]
                fix_resp = client.chat.completions.create(model="gpt-4o", messages=fix_messages, temperature=0)
                step["code"] = fix_resp.choices[0].message.content.strip().strip("```python").strip("```")
                success, output, result = self._execute_step(step)

            results.append({"step": step["step"], "description": step["description"],
                           "success": success, "stdout": output, "result": result})

        insights = self._synthesize_insights(question, results)
        return {"plan": plan, "results": results, "insights": insights}

# Usage
df = pd.read_csv("sales_data.csv")
agent = DataAnalysisAgent(df, "Q3 Sales Data")
analysis = agent.analyze("What drove the 15% revenue decline in September compared to August?")
print(analysis["insights"])
